    def initialize_board(self):
        for row in range(8):
            for col in range(8):
                if (row + col) % 2 == 1:
                    if row < 3:
                        self.pieces[(col, row)] = Piece('red')
                    elif row > 4:
                        self.pieces[(col, row)] = Piece('black')

    def move(self, from_pos, to_pos):
        # Implement move logic here
        pass

    def __str__(self):
        board_str = "  a b c d e f g h\n"
        for row in range(8):
            line = str(row + 1) + "| "
            for col in range(8):
                if (col, row) in self.pieces:
                    piece = self.pieces[(col, row)]
                    line += piece.symbol() + " "
                else:
                    line += ". "
            board_str += line.strip() + "|\n"
